import sys

class Solution:
    def change(self, m: int, coins: list[int]) -> int:
        memo = [0] * (m+1)
        for coin in coins:
            for i in range(coin, m+1):
                memo[i] += 1
        return memo[m]

if __name__ == '__main__':
    Solution = Solution()
    m = int(sys.stdin.readline().strip())
    coins = [int(num) for num in sys.stdin.readline().strip().split()]
    print(Solution.change(m, coins))

