#include <bits/stdc++.h>

using namespace std;

class Solution {
public:
    int change(int m, vector<int>& coins) {
        vector<int> memo(m+1, 0);
        for(int i = 0; i < coins.size(); i++) {
            for(int j = coins[i]; j <= m; j++) {
                if( j % coins[i] == 0 ) { memo[j] = 1; }
                else { memo[j] = memo[j - coins[i]]; }
            }
        }
        return memo[m];
    }
};

int main()
{
    int n;
    cin >> n;
    vector<int> coins(n);
    for(int i = 0; i < n; i++)
    {
        cin >> coins[i];
    }

    Solution s;
    cout << s.change(n, coins);

    return 0;
}
